n = int(input())
s = input()

# dp[i][j] - number of ways to go from 0,0 to i,j

dp = [[0] * (n + 1) for i in range(n + 1)]
dp[0][0] = 1

for i in range(n):
    for j in range(n):
        if s[i] == 'U':
            dp[i + 1][j] += dp[i][j]
        elif s[i] == 'R':
            dp[i][j + 1] += dp[i][j]
        elif s[i] == 'D':
            dp[i - 1][j] += dp[i][j]
        elif s[i] == 'L':
            dp[i][j - 1] += dp[i][j]

print(dp[0][0])

